//#region src/lib/withTriggerCombobox.ts
const withTriggerCombobox = ({ editor, getOptions, tf: { insertText }, type }) => {
	const matchesTrigger = (text) => {
		const { trigger } = getOptions();
		if (trigger instanceof RegExp) return trigger.test(text);
		if (Array.isArray(trigger)) return trigger.includes(text);
		return text === trigger;
	};
	return { transforms: { insertText(text, options) {
		const { createComboboxInput, triggerPreviousCharPattern, triggerQuery } = getOptions();
		if (options?.at || !editor.selection || !matchesTrigger(text) || triggerQuery && !triggerQuery(editor)) return insertText(text, options);
		const previousChar = editor.api.string(editor.api.range("before", editor.selection));
		if (triggerPreviousCharPattern?.test(previousChar)) {
			const inputNode = createComboboxInput ? createComboboxInput(text) : {
				children: [{ text: "" }],
				type
			};
			if (editor.meta.userId) inputNode.userId = editor.meta.userId;
			return editor.tf.insertNodes(inputNode, options);
		}
		return insertText(text, options);
	} } };
};

//#endregion
//#region src/lib/utils/filterWords.ts
const DEFAULT_WORD_BOUNDARY = /\s+/;
const filterWords = (haystack, needle, { prefixMode = "last-word", wordBoundary = DEFAULT_WORD_BOUNDARY, wordQuantifier = "match-all" } = {}) => {
	const haystackWords = haystack.trim().split(wordBoundary);
	const needleWords = needle.trim().split(wordBoundary);
	return needleWords[wordQuantifier === "match-all" ? "every" : "some"]((needleWord, i) => {
		const allowPrefix = (() => {
			switch (prefixMode) {
				case "all-words": return true;
				case "last-word": return i === needleWords.length - 1;
				case "none": return false;
			}
		})();
		return haystackWords.some((unslicedHaystackWord) => {
			return (allowPrefix ? unslicedHaystackWord.slice(0, needleWord.length) : unslicedHaystackWord).localeCompare(needleWord, void 0, {
				sensitivity: "base",
				usage: "search"
			}) === 0;
		});
	});
};

//#endregion
export { filterWords, withTriggerCombobox };